void solve(int CASE)
{
    int n, k; cin >> n >> k;
    var a = vector<int>(n + 1);
    var b = vector<int>(n + 1);
    var pre = vector<int>(n + 1);
    int tot = 0;
    fa(i, 1, n) {
        cin >> a[i];
        b[i] = min(n, i + a[i]);
        pre[i] = max(pre[i - 1], b[i]);
        if (a[i])tot++;
    }

    if (k >= tot) {
        cout << 0 << endl;
        return;
    }

    int id = 0;
    fa(i, 1, n)if (a[i]) {
        id = i;
        break;
    }

    var check = [&](int mid)->bool {
        int cnt = 1, tim = mid - 1; // 初始点个数，时间片剩余
        int r = b[id]; // 初始点最远能染色的点

        fa(i, id, n) if (a[i]) {
            if (i > r) { // 之前的初始点不能到
                if (tim) {
                    r = pre[r];
                    if (i > r) {
                        // 时间段内任何点作为初始点都不能给 i 染色
                        // i 作为初始点，开启新的时间片
                        cnt++;
                        tim = mid - 1;
                        r = b[i];
                    }
                    else tim--; // 能给 i 染色，延用同一段时间
                }
                else {
                    // 时间片用完
                    // 选前 i 个中染色最远的作为起始点，开启新的时间片
                    cnt++;
                    tim = mid - 1;
                    r = pre[i];
                }
            }
        }
        return cnt <= k;
        };

    int l = 1, r = n, ans = -1;
    while (l <= r) {
        int mid = l + r >> 1;
        if (check(mid)) {
            r = mid - 1;
            ans = mid;
        }
        else l = mid + 1;
    }
    cout << ans << endl;
    return;
}
